#include<cstdio>
#include<algorithm>
#include<queue>
#include<cstring>
using namespace std;
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res; 
}
const int dd=1e9;int cnt;
const int N=1010;int a[2][N],n,d,ans[N],T,CC[2][N<<1],cc[2][N<<1],PP[N<<1],pp;
struct Heap
{
	priority_queue<int> h,bin;
	inline void push(int x){h.push(x);}inline void del(int x){bin.push(x);}
	inline int top(){while(!bin.empty()&&bin.top()==h.top())bin.pop(),h.pop();return h.top();}
	inline bool empty(){return h.size()==bin.size();}
	inline void clear(){priority_queue<int> a,b;h.swap(a);bin.swap(b);}
	inline int size(){return h.size()-bin.size();}
}s[2];
inline int fnd(int x){int l=1,r=pp,m;while(l<=r)PP[m=(l+r)>>1]<=x?l=m+1:r=m-1;return l-1;}
inline bool work(int pp0,int pp1,int I,int J)
{
	
	int p[2]={pp0,pp1};memcpy(cc,CC,sizeof(cc));
	--cc[0][fnd(abs(pp0))];--cc[1][fnd(abs(pp1))];
	d=abs(p[0]-p[1]);ans[1]=0;rep(0,1,i)s[i].clear();
	rep(1,n,j)if(j!=I)s[0].push(a[0][j]);
	rep(1,n,j)if(j!=J)s[1].push(a[1][j]);
	int c=1;while(!s[0].empty())
	{
//		printf("%d %d\n",s[0].size(),s[1].size());
		int m[2]={s[0].top(),s[1].top()};
		int i=m[0]>m[1]?0:1;int mx=m[i];s[i].del(mx);--cc[i][fnd(mx)];
		int dlt=abs(d-mx),x=fnd(dlt);if(PP[x]!=dlt||!cc[i^1][x])return false;
		s[i^1].del(dlt);ans[++c]=p[i]-(p[i]>p[i^1]?1:-1)*mx;--cc[i^1][x];
	}
	int dd=2e9;rep(1,c,i)dd=min(dd,ans[i]);dd=min(dd,p[0]);dd=min(dd,p[1]);dd=-dd;
	puts("YES");
	rep(1,c,i)printf("%d ",ans[i]+dd);printf("\n%d %d\n",p[0]+dd,p[1]+dd);
	return true;
}
inline void Solve()
{
	pp=0;n=read();rep(0,1,i)rep(1,n,j)PP[++pp]=a[i][j]=read();
	sort(PP+1,PP+pp+1);pp=unique(PP+1,PP+pp+1)-PP-1;
	memset(CC,0,sizeof(CC));
	rep(0,1,i)rep(1,n,j)++CC[i][fnd(a[i][j])];
	rep(1,n,i)
	{
		if(work(a[0][1],-a[1][i],1,i))return;
		if(work(a[0][1],a[1][i],1,i))return;
	}
	puts("NO");return;
}
int main()
{
//	FIN("data.txt");
